import{_ as e,o,c as r,ag as i}from"./chunks/framework.BCNqqQgW.js";const h=JSON.parse('{"title":"Known Limitations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/limitations.md","filePath":"guide/limitations.md"}'),n={name:"guide/limitations.md"};function s(a,t,d,c,l,m){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Area</th><th>Limitation</th></tr></thead><tbody><tr><td><strong>Standard deviation</strong></td><td>Divides by <code>n</code> not <code>n-1</code>. For typical MCMC chains (n ≥ 500) the difference is &lt; 0.1%, but it is technically a biased estimator. Affects skewness and kurtosis computation too.</td></tr><tr><td><strong>HDI multimodal</strong></td><td>The sliding-window algorithm returns the shortest <em>contiguous</em> interval. For strongly bimodal posteriors this returns the widest single mode. There is no multi-interval HDI.</td></tr><tr><td><strong>No caching</strong></td><td><code>sequenceStats()</code>, <code>variableStats()</code>, and <code>summary()</code> recompute on every call. For large posteriors (&gt; 50k draws × 100 variables), calling <code>summary()</code> in a tight loop is expensive.</td></tr><tr><td><strong><code>densityPlot</code> no spec</strong></td><td><code>densityPlot()</code> and <code>getDensityPlotData()</code> exist but there is no <code>densityPlotSpec()</code>. All other plots have a spec function.</td></tr><tr><td><strong>Missing diagnostics</strong></td><td>No BFMI (critical for HMC/NUTS), no Heidelberger-Welch, no Raftery-Lewis, no nested R-hat, no multivariate PSRF, no R*, no ESS/sec, no posterior correlation matrix, no DIC/LOO-CV.</td></tr><tr><td><strong>Export formats</strong></td><td>Only generic JSON export. No Turing CSV, Stan CSV, or ArviZ JSON re-export.</td></tr><tr><td><strong>ArviZ recursion depth</strong></td><td>The ArviZ JSON parser uses recursion for multi-dimensional parameter flattening. Extremely high-dimensional parameters (&gt; 1000 dimensions) risk stack overflow.</td></tr><tr><td><strong>NetCDF</strong></td><td>Cannot read NetCDF files. <code>netcdfjs</code> only reads NetCDF v3 (classic format), but ArviZ writes NetCDF v4 (HDF5-based). They are not compatible without conversion.</td></tr><tr><td><strong>Autocorrelation inconsistency</strong></td><td>The ACF shown in <code>autocorrelationPlot</code> uses a simple lag formula; the autocorrelation used internally for ESS uses the FFT-based power spectrum. Both are correct but not identical for finite-length chains.</td></tr></tbody></table>',2)])])}const u=e(n,[["render",s]]);export{h as __pageData,u as default};
